func TestVerifySgx(t *testing.T) {
	type args struct {
		evidence       ar.Evidence
		collateral     ar.Collateral
		nonce          []byte
		policy         *ar.SgxPolicy
		caFingerprints []string
		refvals        []ar.Component
	}
	tests := []struct {
		name  string
		args  args
		want  ar.Status
		want1 bool
	}{
		{
			name: "Valid Attestation Report",
			args: args{
				evidence: ar.Evidence{
					Type: ar.TYPE_EVIDENCE_SGX,
					Data: validSGXQuote,
				},
				collateral: ar.Collateral{
					Type:      ar.TYPE_TDX_COLLATERAL,
					Artifacts: sgxCollateralArtifacts,
				},
				caFingerprints: validSgxCaFingerprints,
				policy: &ar.SgxPolicy{
					QuoteVersion: validSGXVersion,
					Attributes:   validSgxAttributes,
					IsvSvn:       validIsvSvn,
					MrSigner:     validMRSIGNER,
					AcceptedTcbStatuses: []string{
						string(pcs.TcbComponentStatusUpToDate),
						string(pcs.TcbComponentStatusOutOfDate),
					},
				},
				refvals: validSgxRefvals,
				nonce:   validSGXNonce,
			},
			want:  ar.StatusSuccess,
			want1: true,
		},
		{
			name: "Invalid Certificate Chain",
			args: args{
				evidence: ar.Evidence{
					Type: ar.TYPE_EVIDENCE_SGX,
					Data: validSGXQuote,
				},
				collateral: ar.Collateral{
					Type:      ar.TYPE_TDX_COLLATERAL,
					Artifacts: sgxCollateralArtifacts,
				},
				caFingerprints: invalidSgxCaFingerprints,
				policy: &ar.SgxPolicy{
					QuoteVersion: validSGXVersion,
					Attributes:   validSgxAttributes,
					IsvSvn:       validIsvSvn,
					MrSigner:     validMRSIGNER,
					AcceptedTcbStatuses: []string{
						string(pcs.TcbComponentStatusUpToDate),
						string(pcs.TcbComponentStatusOutOfDate),
					},
				},
				refvals: validSgxRefvals,
				nonce:   validSGXNonce,
			},
			want:  ar.StatusFail,
			want1: false,
		},
		{
			name: "Invalid Report Signature",
			args: args{
				evidence: ar.Evidence{
					Type: ar.TYPE_EVIDENCE_SGX,
					Data: invalidSGXQuote,
				},
				collateral: ar.Collateral{
					Type:      ar.TYPE_TDX_COLLATERAL,
					Artifacts: sgxCollateralArtifacts,
				},
				caFingerprints: validSgxCaFingerprints,
				policy: &ar.SgxPolicy{
					QuoteVersion: validSGXVersion,
					Attributes:   validSgxAttributes,
					IsvSvn:       validIsvSvn,
					MrSigner:     validMRSIGNER,
					AcceptedTcbStatuses: []string{
						string(pcs.TcbComponentStatusUpToDate),
						string(pcs.TcbComponentStatusOutOfDate),
					},
				},
				refvals: validSgxRefvals,
				nonce:   validSGXNonce,
			},
			want:  ar.StatusFail,
			want1: false,
		},
		{
			name: "Missing Collateral",
			args: args{
				evidence: ar.Evidence{
					Type: ar.TYPE_EVIDENCE_SGX,
					Data: validSGXQuote,
				},
				caFingerprints: validSgxCaFingerprints,
				policy: &ar.SgxPolicy{
					QuoteVersion: validSGXVersion,
					Attributes:   validSgxAttributes,
					IsvSvn:       validIsvSvn,
					MrSigner:     validMRSIGNER,
					AcceptedTcbStatuses: []string{
						string(pcs.TcbComponentStatusUpToDate),
						string(pcs.TcbComponentStatusOutOfDate),
					},
				},
				refvals: validSgxRefvals,
				nonce:   validSGXNonce,
			},
			want:  ar.StatusFail,
			want1: false,
		},
		{
			name: "Invalid Measurement",
			args: args{
				evidence: ar.Evidence{
					Type: ar.TYPE_EVIDENCE_SGX,
					Data: validSGXQuote,
				},
				collateral: ar.Collateral{
					Type:      ar.TYPE_TDX_COLLATERAL,
					Artifacts: sgxCollateralArtifacts,
				},
				caFingerprints: validSgxCaFingerprints,
				policy: &ar.SgxPolicy{
					QuoteVersion: validSGXVersion,
					Attributes:   validSgxAttributes,
					IsvSvn:       validIsvSvn,
					MrSigner:     validMRSIGNER,
					AcceptedTcbStatuses: []string{
						string(pcs.TcbComponentStatusUpToDate),
						string(pcs.TcbComponentStatusOutOfDate),
					},
				},
				refvals: invalidSgxRefvals,
				nonce:   validSGXNonce,
			},
			want:  ar.StatusFail,
			want1: false,
		},
		{
			name: "Invalid Attributes",
			args: args{
				evidence: ar.Evidence{
					Type: ar.TYPE_EVIDENCE_SGX,
					Data: validSGXQuote,
				},
				collateral: ar.Collateral{
					Type:      ar.TYPE_TDX_COLLATERAL,
					Artifacts: sgxCollateralArtifacts,
				},
				caFingerprints: validSgxCaFingerprints,
				policy: &ar.SgxPolicy{
					QuoteVersion: validSGXVersion,
					Attributes:   invalidSgxAttributes,
					IsvSvn:       validIsvSvn,
					MrSigner:     validMRSIGNER,
					AcceptedTcbStatuses: []string{
						string(pcs.TcbComponentStatusUpToDate),
						string(pcs.TcbComponentStatusOutOfDate),
					},
				},
				refvals: validSgxRefvals,
				nonce:   validSGXNonce,
			},
			want:  ar.StatusFail,
			want1: false,
		},
		{
			name: "Invalid Nonce",
			args: args{
				evidence: ar.Evidence{
					Type: ar.TYPE_EVIDENCE_SGX,
					Data: validSGXQuote,
				},
				collateral: ar.Collateral{
					Type:      ar.TYPE_TDX_COLLATERAL,
					Artifacts: sgxCollateralArtifacts,
				},
				caFingerprints: validSgxCaFingerprints,
				policy: &ar.SgxPolicy{
					QuoteVersion: validSGXVersion,
					Attributes:   validSgxAttributes,
					IsvSvn:       validIsvSvn,
					MrSigner:     validMRSIGNER,
					AcceptedTcbStatuses: []string{
						string(pcs.TcbComponentStatusUpToDate),
						string(pcs.TcbComponentStatusOutOfDate),
					},
				},
				refvals: validSgxRefvals,
				nonce:   []byte{},
			},
			want:  ar.StatusFail,
			want1: false,
		},
		{
			name: "Invalid MRSIGNER",
			args: args{
				evidence: ar.Evidence{
					Type: ar.TYPE_EVIDENCE_SGX,
					Data: validSGXQuote,
				},
				collateral: ar.Collateral{
					Type:      ar.TYPE_TDX_COLLATERAL,
					Artifacts: sgxCollateralArtifacts,
				},
				caFingerprints: validSgxCaFingerprints,
				policy: &ar.SgxPolicy{
					QuoteVersion: validSGXVersion,
					Attributes:   validSgxAttributes,
					IsvSvn:       validIsvSvn,
					MrSigner:     invalidMRSIGNER,
					AcceptedTcbStatuses: []string{
						string(pcs.TcbComponentStatusUpToDate),
						string(pcs.TcbComponentStatusOutOfDate),
					},
				},
				refvals: validSgxRefvals,
				nonce:   validSGXNonce,
			},
			want:  ar.StatusFail,
			want1: false,
		},
		{
			name: "Missing SGX Policy",
			args: args{
				evidence: ar.Evidence{
					Type: ar.TYPE_EVIDENCE_SGX,
					Data: validSGXQuote,
				},
				collateral: ar.Collateral{
					Type:      ar.TYPE_TDX_COLLATERAL,
					Artifacts: sgxCollateralArtifacts,
				},
				caFingerprints: validSgxCaFingerprints,
				refvals:        validSgxRefvals,
				nonce:          validSGXNonce,
			},
			want:  ar.StatusFail,
			want1: false,
		},
	}
	logrus.SetLevel(logrus.TraceLevel)

	log.Trace("Fetching TcbInfo")

	// Set the time to a fixed time, as the intel collateral is verified to be not older
	// than one month in the FUT
	fixed := time.Date(2026, 3, 16, 21, 50, 0, 0, time.UTC)
	oldNow := now
	now = func() time.Time { return fixed }
	defer func() { now = oldNow }()

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, got1 := VerifySgx(tt.args.evidence, tt.args.collateral, tt.args.nonce,
				tt.args.policy, tt.args.caFingerprints, tt.args.refvals)
			if got.Summary.Status != tt.want {
				t.Errorf("verifySgx() got = %v, want %v", got.Summary.Status, tt.want)
			}
			if got1 != tt.want1 {
				t.Errorf("verifySgx() got1 = %v, want %v", got1, tt.want)
			}
		})
	}
}

func TestParseSGXExtensions(t *testing.T) {
	type args struct {
		extensions []byte
	}
	tests := []struct {
		name    string
		args    args
		wantErr bool
	}{
		{
			name: "Test parse SGX Extensions",
			args: args{
				extensions: sgx_extensions,
			},
			wantErr: false,
		},
		{
			name: "Test parse SGX Extensions to short",
			args: args{
				extensions: sgx_extensions_short,
			},
			wantErr: true,
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got, err := ParseSGXExtensions(tt.args.extensions)
			if (err != nil) != tt.wantErr {
				t.Errorf("ParseSGXExtensions() error = %v, wantErr %v", err, tt.wantErr)
				fmt.Println(got)
				return
			}
		})
	}
}

